css_styles:
:root {
    --accent-color: #2563eb;  /* Royal Blue */
    --primary-color: #0f172a; /* Slate 900 */
    --text-color: #334155;    /* Slate 700 */
    --muted-color: #64748b;   /* Slate 500 */
    --border-color: #e2e8f0;  /* Slate 200 */
}

@page {
    size: A4;
    margin: 15mm;
}

body {
    font-family: 'Inter', sans-serif;
    color: var(--text-color);
    line-height: 1.45;
    margin: 0;
    padding: 0;
    font-size: 10pt;
}

.resume-container {
    max-width: 100%;
}

.resume-header {
    border-bottom: 2px solid var(--accent-color);
    padding-bottom: 12px;
    margin-bottom: 18px;
}

.candidate-name {
    font-size: 24pt;
    font-weight: 700;
    color: var(--primary-color);
    margin: 0 0 6px 0;
    letter-spacing: -0.5px;
}

.contact-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 8px 16px;
    font-size: 8.5pt;
    color: var(--muted-color);
}

.contact-grid span {
    display: inline-flex;
    align-items: center;
}

.contact-grid a {
    color: var(--muted-color);
    text-decoration: none;
}

.contact-grid a:hover {
    color: var(--accent-color);
    text-decoration: underline;
}

.resume-section {
    margin-bottom: 16px;
    page-break-inside: avoid;
}

.section-title {
    font-size: 11pt;
    font-weight: 700;
    color: var(--accent-color);
    text-transform: uppercase;
    letter-spacing: 0.8px;
    margin: 0 0 8px 0;
    border-bottom: 1px solid var(--border-color);
    padding-bottom: 2px;
}

.section-content {
    padding-left: 2px;
}

.summary-text {
    font-size: 9.5pt;
    text-align: justify;
    margin: 0;
}

.resume-item {
    margin-bottom: 12px;
    page-break-inside: avoid;
}

.resume-item:last-child {
    margin-bottom: 0;
}

.item-header {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
}

.company-name, .project-title, .institution-name {
    font-size: 10pt;
    font-weight: 700;
    color: var(--primary-color);
}

.item-date {
    font-size: 8.5pt;
    font-weight: 500;
    color: var(--muted-color);
}

.item-subheader {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
    margin-top: 1px;
}

.job-title, .degree-name, .project-link {
    font-size: 9pt;
    font-weight: 600;
    color: var(--text-color);
}

.project-link a {
    color: var(--accent-color);
    text-decoration: none;
}

.project-link a:hover {
    text-decoration: underline;
}

.gpa-score {
    font-size: 9pt;
    font-weight: 700;
    color: var(--primary-color);
}

.item-description {
    font-size: 9pt;
    margin: 3px 0 0 0;
    color: var(--text-color);
}

.bullet-list {
    margin: 3px 0 0 0;
    padding-left: 18px;
    font-size: 9pt;
}

.bullet-list li {
    margin-bottom: 2px;
}

.project-tech {
    font-size: 8.5pt;
    margin-top: 2px;
    color: var(--muted-color);
}

.skills-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 8px;
    margin-top: 4px;
}

.skill-card {
    background: #f8fafc;
    border: 1px solid #f1f5f9;
    border-radius: 4px;
    padding: 6px 10px;
}

.skill-category {
    font-size: 8.5pt;
    font-weight: 700;
    color: var(--primary-color);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 2px;
}

.skill-items {
    font-size: 9pt;
    color: var(--text-color);
}

.two-column-grid {
    display: flex;
    justify-content: space-between;
    gap: 16px;
}

.col-6 {
    flex: 1;
}

.issuer {
    color: var(--muted-color);
}

.cert-date {
    color: var(--muted-color);
    font-size: 8.5pt;
}

.ach-desc {
    margin: 1px 0 0 0;
    font-size: 8.5pt;
    color: var(--muted-color);
}

:root {
    --primary-color: #1e3a8a;  /* Deep Navy */
